// Plant monitor: a soil-moisture probe drives an LCD gauge, the on-board
// RGB LED (green = wet, red = dry) and a chirp when the plant is thirsty.
// Drag the soil sensor's level slider in the sim. Readings are millivolts;
// a HIGHER voltage here means DRIER soil.
//
// You are `soil`; `screen` (LCD) and `chirp` (buzzer) are wired nearby.

fn on_start() {
    lcd_init(6, 7, 8, 9, 10);           // ST7735 on SPI2: sck, mosi, cs, dc, rst
    lcd_clear(4, 10, 6);
    lcd_rect(0, 0, 128, 15, 16, 40, 24);
    lcd_text(6, 3, "PLANT MONITOR", 200, 235, 210);
    this.dry = false;
    this.last = -1;
    log("watching soil moisture");
}

fn on_reading(mv) {
    let dryness = mv * 100 / 3300;      // 0 wet .. 100 dry
    let wet = 100 - dryness;

    // Repaint the gauge only when the whole-percent value moves.
    if wet != this.last {
        this.last = wet;
        lcd_rect(8, 40, 112, 16, 20, 24, 20);           // gauge track
        let fill = wet * 112 / 100;
        lcd_rect(8, 40, fill, 16, 60, 200, 90);         // gauge fill
        lcd_rect(8, 66, 120, 14, 4, 10, 6);
        lcd_text(8, 68, `moisture ${wet}%`, 220, 235, 220);
    }

    // Color + alert, with a little hysteresis around the dry threshold.
    rgb(dryness * 255 / 100, wet * 255 / 100, 0);
    if wet < 25 && !this.dry {
        this.dry = true;
        chirp.tone(1200, 200);
        log("thirsty! water me");
    } else if wet > 35 && this.dry {
        this.dry = false;
        log("happy again");
    }
}
